     1→using Microsoft.EntityFrameworkCore;
     2→using WebIde.Model;
     3→
     4→namespace WebIde.DAL;
     5→
     6→public class WebIdeDbContext : DbContext
     7→{
     8→    public WebIdeDbContext(DbContextOptions<WebIdeDbContext> options) : base(options) { }
     9→
    10→    public DbSet<Problem> Problems { get; set; }
    11→    public DbSet<User> Users { get; set; }
    12→    public DbSet<Tag> Tags { get; set; }
    13→    public DbSet<TestCase> TestCases { get; set; }
    14→    public DbSet<Submission> Submissions { get; set; }
    15→    public DbSet<ExecutionResult> ExecutionResults { get; set; }
    16→    public DbSet<Organization> Organizations { get; set; }
    17→    public DbSet<ProblemSet> ProblemSets { get; set; }
    18→
    19→    protected override void OnModelCreating(ModelBuilder modelBuilder)
    20→    {
    21→        base.OnModelCreating(modelBuilder);
    22→
    23→        // N-N: Problem <-> Tag (explicit join table name)
    24→        modelBuilder.Entity<Problem>()
    25→            .HasMany(p => p.Tags)
    26→            .WithMany(t => t.Problems)
    27→            .UsingEntity(j => j.ToTable("ProblemTags"));
    28→
    29→        // N-N: Problem <-> ProblemSet
    30→        modelBuilder.Entity<ProblemSet>()
    31→            .HasMany(ps => ps.Problems)
    32→            .WithMany()
    33→            .UsingEntity(j => j.ToTable("ProblemSetProblems"));
    34→
    35→        // N-N: User <-> Organization
    36→        modelBuilder.Entity<Organization>()
    37→            .HasMany(o => o.Members)
    38→            .WithMany(u => u.Organizations)
    39→            .UsingEntity(j => j.ToTable("OrganizationMembers"));
    40→    }
    41→}
