     1→using Microsoft.EntityFrameworkCore;
     2→using WebIde.DAL;
     3→using WebIde.Model;
     4→
     5→namespace WebIde.Web.Repositories;
     6→
     7→public class UserRepository
     8→{
     9→    private readonly WebIdeDbContext _db;
    10→    public UserRepository(WebIdeDbContext db) => _db = db;
    11→
    12→    public List<User> GetAll() =>
    13→        _db.Users
    14→            .Include(u => u.Submissions).ThenInclude(s => s.Problem)
    15→            .Include(u => u.Organizations)
    16→            .OrderBy(u => u.Id)
    17→            .ToList();
    18→
    19→    public User? GetById(int id) =>
    20→        _db.Users
    21→            .Include(u => u.Submissions).ThenInclude(s => s.Problem)
    22→            .Include(u => u.Organizations).ThenInclude(o => o.ProblemSets)
    23→            .FirstOrDefault(u => u.Id == id);
    24→}
    25→

