     7→namespace WebIde.Web.Controllers;
     8→
     9→public class HomeController : Controller
    10→{
    11→    private readonly ProblemRepository _problems;
    12→    private readonly UserRepository _users;
    13→    private readonly SubmissionRepository _submissions;
    14→
    15→    public HomeController(ProblemRepository problems, UserRepository users, SubmissionRepository submissions)
    16→    {
    17→        _problems = problems;
    18→        _users = users;
    19→        _submissions = submissions;
    20→    }
    21→
    22→    public IActionResult Index()
    23→    {
    24→        var allSubmissions = _submissions.GetAll();
    25→        var vm = new HomeViewModel
    26→        {
    27→            TotalProblems = _problems.GetAll().Count,
    28→            TotalUsers = _users.GetAll().Count,
    29→            TotalSubmissions = allSubmissions.Count,
    30→            AcceptedSubmissions = allSubmissions.Count(s => s.Status == SubmissionStatus.Accepted),
    31→            FeaturedProblems = _problems.GetAll().Take(3).ToList(),
    32→            TopUsers = _users.GetAll()
    33→                .Select(u => (u, u.Submissions.Count(s => s.Status == SubmissionStatus.Accepted)))
    34→                .OrderByDescending(x => x.Item2)
    35→                .Take(3)
    36→                .ToList()
    37→        };
    38→        ViewData["Title"] = "HOME";
    39→        return View(vm);
    40→    }
    41→
    42→    [ResponseCache(Duration = 0, Location = ResponseCacheLocation.None, NoStore = true)]
    43→    public IActionResult Error()
    44→    {
    45→        return View(new ErrorViewModel { RequestId = Activity.Current?.Id ?? HttpContext.TraceIdentifier });
    46→    }
    47→}
    48→

