     1→using Microsoft.AspNetCore.Mvc;
     2→using WebIde.Model.Enums;
     3→using WebIde.Web.Repositories;
     4→
     5→namespace WebIde.Web.Controllers;
     6→
     7→[Route("problems")]
     8→public class ProblemController : Controller
     9→{
    10→    private readonly ProblemRepository _repo;
    11→    private readonly SubmissionRepository _submissions;
    12→
    13→    public ProblemController(ProblemRepository repo, SubmissionRepository submissions)
    14→    {
    15→        _repo = repo;
    16→        _submissions = submissions;
    17→    }
    18→
    19→    [Route("")]
    20→    public IActionResult Index(string? sort)
    21→    {
    22→        var problems = _repo.GetAll();
    23→
    24→        problems = sort switch
    25→        {
    26→            "difficulty-asc"  => problems.OrderBy(p => p.Difficulty).ToList(),
    27→            "difficulty-desc" => problems.OrderByDescending(p => p.Difficulty).ToList(),
    28→            "title"           => problems.OrderBy(p => p.Title).ToList(),
    29→            "acceptance-asc"  => problems.OrderBy(p =>
    30→                p.Submissions.Count == 0 ? 0 : (double)p.Submissions.Count(s => s.Status == SubmissionStatus.Accepted) / p.Submissions.Count).ToList(),
    31→            "acceptance-desc" => problems.OrderByDescending(p =>
    32→                p.Submissions.Count == 0 ? 0 : (double)p.Submissions.Count(s => s.Status == SubmissionStatus.Accepted) / p.Submissions.Count).ToList(),
    33→            _                 => problems.OrderBy(p => p.Id).ToList(),
    34→        };
    35→
    36→        ViewData["Title"] = "PROBLEMS";
    37→        ViewData["sort"] = sort ?? "";
    38→        return View(problems);
    39→    }
    40→
    41→    [Route("{id:int}")]
    42→    public IActionResult Details(int id)
    43→    {
    44→        var problem = _repo.GetById(id);
    45→        if (problem is null) return NotFound();
    46→        ViewData["Title"] = problem.Title.ToUpper();
    47→        return View(problem);
    48→    }
    49→}
    50→

