            return View(model);
        }
        _repo.Add(new User
        {
            Username    = model.Username,
            Email       = model.Email,
            DisplayName = model.DisplayName,
            Role        = model.Role,
            RegisteredAt = model.RegisteredAt,
        });
        TempData["Flash"] = $"User \"{model.Username}\" created.";
        return RedirectToAction(nameof(Index));
    }

    [Route("{id:int}/edit")]
    [HttpGet, ActionName("Edit")]
