        var user = _repo.GetById(id);
        if (user is null) return NotFound();
        user.Username    = model.Username;
        user.Email       = model.Email;
        user.DisplayName = model.DisplayName;
        user.Role        = model.Role;
        user.RegisteredAt = model.RegisteredAt;
